380: // attachCiliumNet attaches programs from bpf_host.c to cilium_net.
381: func attachCiliumNet(cfg *datapath.LocalNodeConfiguration, ep datapath.Endpoint, spec *ebpf.CollectionSpec) error {
382: 	net, err := safenetlink.LinkByName(defaults.SecondHostDevice)
383: 	if err != nil {
384: 		return fmt.Errorf("retrieving device %s: %w", defaults.SecondHostDevice, err)
385: 	}
386: 
387: 	consts, renames, err := hostRewrites(cfg, ep, defaults.SecondHostDevice)
388: 	if err != nil {
389: 		return err
390: 	}
391: 
392: 	var netObj hostNetObjects
393: 	commit, err := bpf.LoadAndAssign(&netObj, spec, &bpf.CollectionOptions{
394: 		CollectionOptions: ebpf.CollectionOptions{
395: 			Maps: ebpf.MapOptions{PinPath: bpf.TCGlobalsPath()},
396: 		},
397: 		MapRenames: renames,
398: 		Constants:  consts,
399: 	})
400: 	if err != nil {
401: 		return err
402: 	}
403: 	defer netObj.Close()
404: 
405: 	// Attach cil_to_host to cilium_net.
406: 	if err := attachSKBProgram(net, netObj.ToHost, symbolToHostEp,
407: 		bpffsDeviceLinksDir(bpf.CiliumPath(), net), netlink.HANDLE_MIN_INGRESS, option.Config.EnableTCX); err != nil {
408: 		return fmt.Errorf("interface %s ingress: %w", defaults.SecondHostDevice, err)
409: 	}
410: 
411: 	if err := commit(); err != nil {
412: 		return fmt.Errorf("committing bpf pins: %w", err)
413: 	}
414: 
415: 	return nil
416: }
